/**
 * Generiert src/lib/learning/drills/apExamDrillData.ts (~45+ Übungen/LF, IHK AP1/AP2).
 * Ausführen: node scripts/generate-ap-exam-drills.mjs
 */
import { writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const outPath = join(__dirname, "../src/lib/learning/drills/apExamDrillData.ts");

/** @typedef {{ id: string, title: string, problem: string, solution: string, question: string, correct: string, wrong: [string,string,string], hints?: [string,string,string], lang?: string }} Drill */

function mc(id, title, problem, solution, question, correct, wrong, hints, lang) {
  const d = { id, title, problem, solution, question, correct, wrong };
  if (hints) d.hints = hints;
  if (lang) d.lang = lang;
  return d;
}

/** @param {Array<[string,string,string,string,string,string,[string,string,string], [string,string,string]?, string?]>} rows */
function bulk(rows) {
  return rows.map((r) => mc(r[0], r[1], r[2], r[3], r[4], r[5], r[6], r[7], r[8]));
}

/** @param {Array<{id:string,title:string,problem:string,solution:string,question:string,correct:string,wrong:[string,string,string],hints?:[string,string,string],lang?:string}>} specs */
function fromSpecs(specs) {
  return specs.map((s) => mc(s.id, s.title, s.problem, s.solution, s.question, s.correct, s.wrong, s.hints, s.lang));
}

function subnetDrills() {
  const specs = [
    { prefix: 24, net: "192.168.10.0", hosts: 254, mask: "255.255.255.0", wrong: ["510", "62", "1022"] },
    { prefix: 25, net: "192.168.1.0", hosts: 126, mask: "255.255.255.128", wrong: ["254", "30", "510"] },
    { prefix: 26, net: "10.10.0.0", hosts: 62, mask: "255.255.255.192", wrong: ["126", "14", "254"] },
    { prefix: 27, net: "172.16.0.0", hosts: 30, mask: "255.255.255.224", wrong: ["62", "6", "126"] },
    { prefix: 28, net: "10.0.0.0", hosts: 14, mask: "255.255.255.240", wrong: ["30", "2", "62"] },
    { prefix: 29, net: "192.168.1.0", hosts: 6, mask: "255.255.255.248", wrong: ["14", "30", "62"] },
    { prefix: 30, net: "10.0.1.0", hosts: 2, mask: "255.255.255.252", wrong: ["6", "14", "4"] },
    { prefix: 31, net: "10.0.0.0", hosts: 0, mask: "255.255.255.254", wrong: ["2", "6", "1"] },
  ];
  return specs.map((s) =>
    mc(
      `subnet-slash${s.prefix}`,
      `Subnetting /${s.prefix}`,
      `Gegeben: ${s.net}/${s.prefix}. Wie viele nutzbare Host-Adressen gibt es?`,
      `/${s.prefix}: 2^${32 - s.prefix} Adressen minus Netz- und Broadcast-Adresse → ${s.hosts} Hosts`,
      "Anzahl nutzbarer Host-Adressen?",
      String(s.hosts),
      s.wrong,
      [`Formel: 2^(32-${s.prefix}) − 2`, `Subnetzmaske ${s.mask}`, "Netz- und Broadcast zählen nicht als Hosts"]
    )
  );
}

