function q(s) {
  return JSON.stringify(s);
}

function drillToTs(d) {
  const lines = [
    `    {`,
    `      id: ${q(d.id)},`,
    `      title: ${q(d.title)},`,
    `      problem: ${q(d.problem)},`,
    `      solution: ${q(d.solution)},`,
    `      question: ${q(d.question)},`,
    `      correct: ${q(d.correct)},`,
    `      wrong: [${d.wrong.map(q).join(", ")}],`,
  ];
  if (d.hints) lines.push(`      hints: [${d.hints.map(q).join(", ")}],`);
  if (d.lang) lines.push(`      lang: ${q(d.lang)},`);
  lines.push(`    },`);
  return lines.join("\n");
}

function emitTs(drillsByLf) {
  const lfs = Object.keys(drillsByLf);
  const blocks = lfs.map((lf) => {
    const drills = drillsByLf[lf];
    return `  ${lf}: [\n${drills.map(drillToTs).join("\n")}\n  ],`;
  });
  return `/** Auto-generated by scripts/generate-ap-exam-drills.mjs — nicht manuell bearbeiten. */
export type ApExamDrill = {
  id: string;
  title: string;
  problem: string;
  solution: string;
  question: string;
  correct: string;
  wrong: [string, string, string];
  hints?: [string, string, string];
  lang?: "sql" | "javascript" | "csharp" | "bash" | "plain-text" | "markdown";
};

export const AP_EXAM_DRILLS_BY_LF: Record<
  "LF1" | "LF2" | "LF3" | "LF4" | "LF5" | "LF6" | "LF7" | "LF8" | "LF9" | "LF10" | "LF11" | "LF12",
  ApExamDrill[]
> = {
${blocks.join("\n")}
};
`;
}

const AP_EXAM_DRILLS_BY_LF = {
  LF1,
  LF2,
  LF3,
  LF4,
  LF5,
  LF6,
  LF7,
  LF8,
  LF9,
  LF10,
  LF11,
  LF12,
};

const MIN_PER_LF = 45;
for (const [lf, arr] of Object.entries(AP_EXAM_DRILLS_BY_LF)) {
  if (!Array.isArray(arr) || arr.length < MIN_PER_LF) {
    throw new Error(`${lf}: expected >= ${MIN_PER_LF} drills, got ${arr?.length ?? 0}`);
  }
  const ids = new Set();
  for (const d of arr) {
    if (ids.has(d.id)) throw new Error(`${lf}: duplicate id ${d.id}`);
    ids.add(d.id);
  }
}

writeFileSync(outPath, emitTs(AP_EXAM_DRILLS_BY_LF), "utf8");
const counts = Object.fromEntries(Object.entries(AP_EXAM_DRILLS_BY_LF).map(([k, v]) => [k, v.length]));
console.log("Wrote", outPath);
console.log("Counts:", counts);
